import zeep
from zeep import Client
from zeep.exceptions import Fault
import re
from lxml import etree


def sanitize_input(value):
    """Sanitize user input to prevent XML injection attacks"""
    if value is None:
        return ""
    
    value = str(value)
    
    # Remove any XML special characters and control characters
    value = value.replace('&', '&amp;')
    value = value.replace('<', '&lt;')
    value = value.replace('>', '&gt;')
    value = value.replace('"', '&quot;')
    value = value.replace("'", '&apos;')
    
    # Remove control characters except tab, newline, and carriage return
    value = ''.join(char for char in value if ord(char) >= 32 or char in '\t\n\r')
    
    # Remove any CDATA section attempts
    value = value.replace('<![CDATA[', '')
    value = value.replace(']]>', '')
    
    # Remove XML processing instructions
    value = re.sub(r'<\?.*?\?>', '', value)
    
    # Remove XML comments
    value = re.sub(r'<!--.*?-->', '', value)
    
    # Remove DOCTYPE declarations
    value = re.sub(r'<!DOCTYPE.*?>', '', value, flags=re.DOTALL)
    
    # Remove entity references except the standard ones we already escaped
    value = re.sub(r'&(?!amp;|lt;|gt;|quot;|apos;)[^;]+;', '', value)
    
    return value


def validate_policy_number(policy_number):
    """Validate policy number format"""
    policy_number = sanitize_input(policy_number)
    
    # Only allow alphanumeric characters and hyphens
    if not re.match(r'^[A-Za-z0-9\-]{1,50}$', policy_number):
        raise ValueError("Invalid policy number format. Only alphanumeric characters and hyphens allowed.")
    
    return policy_number


def validate_customer_name(customer_name):
    """Validate customer name format"""
    customer_name = sanitize_input(customer_name)
    
    # Only allow letters, spaces, hyphens, and apostrophes
    if not re.match(r'^[A-Za-z\s\-\']{1,100}$', customer_name):
        raise ValueError("Invalid customer name format. Only letters, spaces, hyphens, and apostrophes allowed.")
    
    return customer_name


def lookup_policy(wsdl_url, policy_number, customer_name):
    """
    Lookup insurance policy using SOAP service
    
    Args:
        wsdl_url: URL to the SOAP WSDL
        policy_number: Policy number to lookup
        customer_name: Customer name associated with the policy
    
    Returns:
        Policy information from the service
    """
    try:
        # Validate and sanitize inputs
        safe_policy_number = validate_policy_number(policy_number)
        safe_customer_name = validate_customer_name(customer_name)
        
        # Create SOAP client with security settings
        settings = zeep.Settings(
            strict=True,
            xml_huge_tree=False,
            forbid_dtd=True,
            forbid_entities=True,
            forbid_external=True
        )
        
        client = Client(wsdl_url, settings=settings)
        
        # Use zeep's built-in type system to create the request
        # This prevents XML injection by properly escaping values
        response = client.service.PolicyLookup(
            PolicyNumber=safe_policy_number,
            CustomerName=safe_customer_name
        )
        
        return response
        
    except Fault as fault:
        print(f"SOAP Fault occurred: {fault}")
        raise
    except ValueError as ve:
        print(f"Validation error: {ve}")
        raise
    except Exception as e:
        print(f"Error occurred: {e}")
        raise


